// uapiConfig renders cfg into the newline-delimited UAPI set string the engine's
// IpcSet consumes. Keys are lowercase hex (UAPI's on-the-wire encoding), NOT the
// base64 form the TOML carries. Amnezia obfuscation keys are emitted only when the
// block is configured; an all-zero Amnezia block leaves the engine in plain
// WireGuard mode. The same amnezia parameters are applied on BOTH roles (edge and
// concentrator) as defense-in-depth — they must match end to end for the handshake
// to succeed (config validation makes each end specify a complete profile, D1).
func uapiConfig(cfg *config.Config, bootEndpoints []bootEndpoint) (string, error) {
	var b strings.Builder

	priv := cfg.WireGuard.PrivateKey.Bytes()
	fmt.Fprintf(&b, "private_key=%s\n", hex.EncodeToString(priv[:]))
	if cfg.Role == config.RoleConcentrator {
		fmt.Fprintf(&b, "listen_port=%d\n", cfg.WireGuard.ListenPort)
	}
	writeAmnezia(&b, cfg.Amnezia)

	for i, peer := range cfg.WireGuard.Peers {
		pub := peer.PublicKey.Bytes()
		fmt.Fprintf(&b, "public_key=%s\n", hex.EncodeToString(pub[:]))
		// The engine peer's endpoint is built ONLY from a resolved flattened entry (Q30): the
		// boot endpoint is the head of the peer's seeded failoverSpecs — a literal's fixed address
		// for an all-literal peer (byte-for-byte the pre-G5 render, Endpoints[0]), or a hostname's
		// boot-resolved head. When nothing resolved (a hostname peer whose name did not resolve in
		// the boot window, or a resolver-less concentrator peer with no endpoint at all) the boot
		// endpoint is INVALID and no endpoint line is emitted — the peer boots endpoint-less
		// (tolerant boot), and for a hostname peer the re-resolution loop installs it on first
		// success (R70). Switching to a standby endpoint on hub loss is the failover controller's
		// job, not this initial render.
		if ep := bootEndpoints[i]; ep.valid {
			fmt.Fprintf(&b, "endpoint=%s\n", ep.ap.String())
			// A keepalive keeps the edge->concentrator session warm and lets the
			// concentrator relearn the edge endpoint after a NAT rebind; only the
			// initiating (edge) side sets it.
			fmt.Fprintf(&b, "persistent_keepalive_interval=%d\n", keepaliveSeconds)
		}
		if len(peer.AllowedIPs) == 0 {
			return "", fmt.Errorf("peer %d (%s): at least one allowed_ip is required", i, hex.EncodeToString(pub[:8]))
		}
		for _, cidr := range peer.AllowedIPs {
			fmt.Fprintf(&b, "allowed_ip=%s\n", cidr)
		}
	}
	return b.String(), nil
}

// keepaliveSeconds is the edge's persistent-keepalive interval.
const keepaliveSeconds = 25

// writeAmnezia emits the nine amneziawg obfuscation UAPI keys, but only when the
// block is configured. When amnezia is unused, wanbond leaves the engine's
// PROCESS-GLOBAL message-type state untouched (see the amneziaGuard invariant).
// Config validation guarantees a configured block is complete and self-consistent
// (D1), and applyDefaults has already filled the standard magic headers (1..4)
// when they were omitted, so the emitted set never carries an h*=0 sentinel.
func writeAmnezia(b *strings.Builder, a config.Amnezia) {
	if !a.Configured() {
		return
	}
	fmt.Fprintf(b, "jc=%d\njmin=%d\njmax=%d\ns1=%d\ns2=%d\nh1=%d\nh2=%d\nh3=%d\nh4=%d\n",
		a.Jc, a.Jmin, a.Jmax, a.S1, a.S2, a.H1, a.H2, a.H3, a.H4)
}

}

// WireGuard holds the inner tunnel's key material.
type WireGuard struct {
	PrivateKey Key    `toml:"private_key"`
	Peers      []Peer `toml:"peers"`
	// ListenPort is the UDP port the concentrator listens on; 0 on the edge.
	ListenPort uint16 `toml:"listen_port"`
}

// Peer is one WireGuard peer.
type Peer struct {
	PublicKey Key `toml:"public_key"`
	// Endpoint is the peer's SINGLE tunnel address (edge -> concentrator); the
	// legacy single-endpoint config form, mutually exclusive with EndpointsRaw.
	// Empty on the concentrator, which roams the edge's endpoint dynamically.
	// A bare `endpoint = "..."` is normalized in resolveEndpoints to a one-
	// element Endpoints list, so it stays behavior-identical to the pre-T54
	// config surface.
	Endpoint string `toml:"endpoint"`
	// EndpointsRaw is the ORDERED list of concentrator (peer) endpoint address:port
	// strings for the edge-side hub-failover config surface (Q18): index 0 is the
	// active/primary concentrator, the rest are ordered standbys. Edge-only; a
	// concentrator declaring it is a config error (validate). Mutually exclusive
	// with the legacy Endpoint field.
	EndpointsRaw []string `toml:"endpoints"`
	// Endpoints is EndpointsRaw (or the single legacy Endpoint, as a one-element
	// list) parsed to netip.AddrPort and de-duplicated; populated by
	// resolveEndpoints in normalize(). This is the shape T57's hub-failover
	// switch consumes: Endpoints[0] is the active concentrator, Endpoints[1:]
	// are the ordered standbys to fail over to in order when all paths to the
	// active one are down. A hostname entry (Q35) contributes NO element here at
	// load time — resolution happens at runtime, not at config load (Q30) — so
	// Endpoints only ever holds the literal-address entries, in order.
	Endpoints []netip.AddrPort `toml:"-"`
	// DNS is the explicit per-peer opt-in (Q29) for hostname endpoint entries: a
	// hostname entry in endpoint/endpoints without dns = true is a config load
	// error naming this flag. Default-off, so an existing IP-literal config never
	// takes a new code path. Edge-only; a concentrator declaring dns = true is a
	// config error, mirroring the endpoints-not-meaningful-for-concentrator rule.
	DNS bool `toml:"dns"`
	// EndpointSpecs is the ordered, typed per-entry parse of the endpoint/
	// endpoints entries (Q35): each entry is either a literal address:port
	// (IsName=false, Addr set — parsed with EXACTLY today's netip.ParseAddrPort
	// path) or, when DNS opts in, a hostname:port (IsName=true, Host/Port set).
	// Populated by resolveEndpoints in normalize(); order matches the TOML list.
	EndpointSpecs []EndpointSpec `toml:"-"`
	// AllowedIPs are the CIDR ranges routed to this peer.
	AllowedIPs []string `toml:"allowed_ips"`
	// PSK is this peer's per-peer override of the outer-control PSK (G4
	// multi-peer concentrator groundwork). With a single configured peer it
	// must be left UNSET: the top-level Config.PSK remains the single-peer
	// default, so a legacy single-peer config carrying only the top-level
	// `psk` parses and behaves byte-identically to before this field existed.
	// With more than one peer, validate requires it to be present and
	// pairwise-distinct across peers (T81, Q21) — the top-level psk alone
	// cannot discriminate which peer authenticated an inbound frame, and equal
	// per-peer psks would defeat that authenticated demux. No datapath code
	// path consumes PSK yet; it is parsed, validated, and exposed only.
	PSK Key `toml:"psk"`
	// Name is this peer's human-readable identifier (G4 multi-peer
	// concentrator groundwork), analogous to Path.Name. Unused and optional
	// with a single peer; required and must be unique across peers when more
	// than one is configured (T81, Q21). Not yet consumed by any datapath code
	// path.
	Name string `toml:"name"`
}

