		"allowed_ips = [\"0.0.0.0/0\"]\nmode = \"default-route\"", 1)
	path := writeConfig(t, 0o600, body)
	c, err := Load(path)
	if err != nil {
		t.Fatalf("Load: %v", err)
	}
	if got := c.WireGuard.Peers[0].Mode; got != PeerModeDefaultRoute {
		t.Errorf("peer 0 mode = %q, want %q", got, PeerModeDefaultRoute)
	}
}

